import{_ as t}from"./chunks/plan_view_overview.CGA8Iu_Y.js";import{_ as a,o as i,c as o,ag as n}from"./chunks/framework.B9unkguw.js";const g=JSON.parse('{"title":"Plan View","description":"","frontmatter":{},"headers":[],"relativePath":"en/qgc-user-guide/plan_view/plan_view.md","filePath":"en/qgc-user-guide/plan_view/plan_view.md"}'),s={name:"en/qgc-user-guide/plan_view/plan_view.md"};function l(r,e,h,d,p,m){return i(),o("div",null,e[0]||(e[0]=[n('<h1 id="plan-view" tabindex="-1">Plan View <a class="header-anchor" href="#plan-view" aria-label="Permalink to &quot;Plan View&quot;">​</a></h1><p>The <em>Plan View</em> is used to plan <em>autonomous missions</em> for your vehicle, and upload them to the vehicle. Once the mission is <a href="#plan_mission">planned</a> and sent to the vehicle, you switch to the <a href="./../fly_view/fly_view.html">Fly View</a> to fly the mission.</p><p>It is also used to configure the <a href="./plan_geofence.html">GeoFence</a> and <a href="./plan_rally_points.html">Rally Points</a> if these are supported by the firmware.</p><p><a id="plan_screenshot"></a><img src="'+t+'" alt="Plan View"></p><h2 id="ui_overview" tabindex="-1">UI Overview <a class="header-anchor" href="#ui_overview" aria-label="Permalink to &quot;UI Overview {#ui_overview}&quot;">​</a></h2><p>The <a href="#plan_screenshot">screenshot above</a> shows the Plan View with an empty mission. The map is centered on the <a href="#planned_home">Planned Home</a> position (H).</p><p>The main elements of the UI are:</p><ul><li><strong>Map:</strong> Displays the numbered indicators for the current mission, including the <a href="#planned_home">Planned Home</a>. Click on the indicators to select them (for editing) or drag them around to reposition them. Flight path lines and direction arrows show the planned route between waypoints.</li><li><strong>Plan Toolbar:</strong> Located at the top of the view with buttons for <strong>Open</strong>, <strong>Save</strong>, <strong>Upload</strong>, and <strong>Clear</strong>. A hamburger menu (☰) provides additional options such as <em>Save as KML</em> and <em>Download</em> (load plan from vehicle). The <strong>Save</strong> and <strong>Upload</strong> buttons are highlighted when there are unsaved or un-uploaded changes.</li><li><strong><a href="#plan_tools">Plan Tools</a>:</strong> A vertical tool strip on the left side of the map used to add mission items (Takeoff, Waypoint, Pattern, ROI, Return/Land) and toggle the stats panel.</li><li><strong><a href="#plan_editor_panel">Plan Editor Panel</a>:</strong> A collapsible tree view on the right side containing the plan file info, mission items, GeoFence, and rally point editors.</li><li><strong>Layer Switcher:</strong> Buttons in the top-right area for switching between <strong>Mission</strong>, <strong>Geo-Fence</strong>, and <strong>Rally Point</strong> editing layers.</li><li><strong>Mission Stats / Terrain Panel:</strong> A panel at the bottom of the map that can toggle between a terrain altitude profile chart (height AMSL vs. distance) and mission statistics (selected waypoint info, total distance, max telemetry distance, estimated flight time, and battery info).</li></ul><h2 id="plan_mission" tabindex="-1">Planning a Mission <a class="header-anchor" href="#plan_mission" aria-label="Permalink to &quot;Planning a Mission {#plan_mission}&quot;">​</a></h2><p>At a very high level, the steps to create a mission are:</p><ol><li>Change to <em>Plan View</em>.</li><li>Add waypoints or commands to the mission and edit as needed.</li><li>Upload the mission to the vehicle.</li><li>Change to <em>Fly View</em> and fly the mission.</li></ol><p>The following sections explain some of the details in the view.</p><h2 id="planned_home" tabindex="-1">Planned Home Position <a class="header-anchor" href="#planned_home" aria-label="Permalink to &quot;Planned Home Position {#planned_home}&quot;">​</a></h2><p>The <em>Planned Home</em> shown in <em>Plan View</em> is used to set the approximate start point when planning a mission (i.e. when a vehicle may not even be connected to QGC). It is used by QGC to estimate mission times and to draw waypoint lines.</p><p>You should move/drag the planned home position to roughly the location where you plan to takeoff. The altitude for the planned home position is determined automatically from terrain data.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The Fly View displays the <em>actual</em> home position set by the vehicle firmware when it arms (this is where the vehicle will return in Return/RTL mode).</p></div><h2 id="plan_tools" tabindex="-1">Plan Tools <a class="header-anchor" href="#plan_tools" aria-label="Permalink to &quot;Plan Tools {#plan_tools}&quot;">​</a></h2><p>The plan tools are a vertical tool strip on the left side of the map, used for adding mission items. The tools are only visible when editing the Mission layer. The main tools (top to bottom) are described below.</p><h3 id="takeoff" tabindex="-1">Takeoff <a class="header-anchor" href="#takeoff" aria-label="Permalink to &quot;Takeoff&quot;">​</a></h3><p>Inserts a takeoff command into the mission. This tool is available for all vehicle types except rovers.</p><h3 id="pattern" tabindex="-1">Pattern <a class="header-anchor" href="#pattern" aria-label="Permalink to &quot;Pattern&quot;">​</a></h3><p>The <a href="./pattern.html">Pattern</a> tool simplifies the creation of missions for flying complex geometries, including <a href="./../plan_view/pattern_survey.html">surveys</a> and <a href="./../plan_view/pattern_structure_scan_v2.html">structure scans</a>. If multiple pattern types are available for the vehicle, clicking the button opens a dropdown to select from Survey, Corridor Scan, Structure Scan, and landing patterns.</p><h3 id="waypoint" tabindex="-1">Waypoint <a class="header-anchor" href="#waypoint" aria-label="Permalink to &quot;Waypoint&quot;">​</a></h3><p>Click the <strong>Waypoint</strong> tool to toggle waypoint-on-click mode. While active, clicking on the map will add a new mission waypoint at the clicked location. The tool stays active until you click it again to deactivate. Once you have added a waypoint, you can select it and drag it around to reposition it.</p><h3 id="roi" tabindex="-1">ROI <a class="header-anchor" href="#roi" aria-label="Permalink to &quot;ROI&quot;">​</a></h3><p>Toggles Region of Interest mode. When active, clicking on the map sets an ROI location. This tool is only visible if the vehicle firmware supports ROI mode.</p><h3 id="return-land" tabindex="-1">Return / Land <a class="header-anchor" href="#return-land" aria-label="Permalink to &quot;Return / Land&quot;">​</a></h3><p>Adds a return or land command to the mission. The label varies by vehicle type:</p><ul><li><strong>Multicopters:</strong> <em>Return</em></li><li><strong>Fixed-wing:</strong> <em>Land</em> (or <em>Alt Land</em> if a land item already exists in the mission)</li></ul><h3 id="stats" tabindex="-1">Stats <a class="header-anchor" href="#stats" aria-label="Permalink to &quot;Stats&quot;">​</a></h3><p>Toggles the <a href="#stats_terrain">Mission Stats / Terrain panel</a> at the bottom of the map. Only visible when that panel is currently hidden.</p><h2 id="file" tabindex="-1">File Operations <a class="header-anchor" href="#file" aria-label="Permalink to &quot;File Operations {#file}&quot;">​</a></h2><p>File operations are located in the <strong>Plan Toolbar</strong> at the top of the view:</p><ul><li><strong>Open</strong> — Load a plan from a file.</li><li><strong>Save</strong> — Save the current plan to a file. Highlighted when there are unsaved changes.</li><li><strong>Upload</strong> — Upload the plan to the vehicle. Highlighted when the plan has un-uploaded changes.</li><li><strong>Clear</strong> — Remove all mission items, geofence, and rally points. If connected to a vehicle, also clears them from the vehicle.</li><li><strong>Hamburger menu</strong> (☰) — Additional options: <ul><li><em>Save as KML</em> — Export the plan as a KML file.</li><li><em>Download</em> — Download the current plan from the vehicle (only available when connected).</li></ul></li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Before you fly a mission you must upload it to the vehicle.</p></div><h2 id="plan_editor_panel" tabindex="-1">Plan Editor Panel <a class="header-anchor" href="#plan_editor_panel" aria-label="Permalink to &quot;Plan Editor Panel {#plan_editor_panel}&quot;">​</a></h2><p>The Plan Editor Panel is a collapsible tree view on the right side of the view. The panel can be collapsed or expanded using the toggle button on its left edge. It is organized into the following collapsible sections: <strong>Plan Info</strong>, <strong>Defaults</strong>, <strong>Mission</strong>, <strong>GeoFence</strong>, <strong>Rally Points</strong>, and <strong>Transform</strong>.</p><h3 id="layer_switcher" tabindex="-1">Layer Switcher <a class="header-anchor" href="#layer_switcher" aria-label="Permalink to &quot;Layer Switcher {#layer_switcher}&quot;">​</a></h3><p>Buttons in the top-right area of the map allow switching between the <strong>Mission</strong>, <strong>Geo-Fence</strong>, and <strong>Rally Point</strong> editing layers. The active layer button is always visible; the other layer buttons slide in briefly when toggled and auto-hide after a few seconds.</p><h3 id="plan_info" tabindex="-1">Plan Info <a class="header-anchor" href="#plan_info" aria-label="Permalink to &quot;Plan Info {#plan_info}&quot;">​</a></h3><p>The Plan Info section contains general plan-level settings:</p><ul><li><strong>Plan File</strong> — An editable name for the plan file.</li><li><strong>Vehicle Info</strong> — Firmware and vehicle type selectors. When connected to a vehicle these are determined automatically; when planning offline you must set them before adding any mission items so that the correct mission commands are available.</li><li><strong>Expected Home Position</strong> — The altitude (AMSL) for the planned home position is determined automatically from terrain data. A <strong>Move To Map Center</strong> button repositions the home marker to the center of the map. This is only the <em>planned</em> home position for estimating mission times and drawing waypoint lines — the actual home position is set by the vehicle when it arms.</li></ul><h3 id="mission_settings" tabindex="-1">Defaults <a class="header-anchor" href="#mission_settings" aria-label="Permalink to &quot;Defaults {#mission_settings}&quot;">​</a></h3><p>The Defaults section sets plan-wide values that apply to new mission items:</p><ul><li><strong>Altitude Frame</strong> — Select the altitude reference frame for waypoints.</li><li><strong>Waypoints Altitude</strong> — The default altitude for the first mission item added (subsequent items take their initial altitude from the previous item). Changing this value when items already exist will prompt to update all items to the new altitude.</li><li><strong>Flight Speed</strong> — Set a flight speed that differs from the default mission speed.</li><li><strong>Vehicle Speeds</strong> — Cruise speed (fixed-wing) and/or hover speed (multi-rotor/VTOL), used for estimating mission time.</li></ul><h3 id="mission_items" tabindex="-1">Mission Items <a class="header-anchor" href="#mission_items" aria-label="Permalink to &quot;Mission Items {#mission_items}&quot;">​</a></h3><p>The Mission section lists all mission items (waypoints, commands, patterns, etc.) in order. Each item can be expanded to edit its parameters.</p><ul><li>Click an item to select it on the map and expand its editor.</li><li>Click the <strong>command name</strong> dropdown to change the item type. A dialog shows &quot;Basic Commands&quot; by default; use the <strong>Category</strong> dropdown to see all available commands.</li><li>Each item has a <strong>hamburger menu</strong> (☰) with options such as <em>Show all values</em>, <em>Move to vehicle position</em>, <em>Move to previous item position</em>, and <em>Edit position</em>.</li><li>A <strong>delete button</strong> (trash icon) removes the item.</li><li>Items that are incomplete or missing required values show a <strong>?</strong> status indicator.</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>The list of available commands depends on firmware and vehicle type. Examples include: Waypoint, Start image capture, Jump to item (to repeat mission), and other commands.</p></div><h4 id="initial-camera-settings" tabindex="-1">Initial Camera Settings <a class="header-anchor" href="#initial-camera-settings" aria-label="Permalink to &quot;Initial Camera Settings&quot;">​</a></h4><p>This allows you to set camera options before any mission items take place. This includes camera actions (take photos by time/distance, start/stop video recording) and gimbal control.</p><h3 id="geofence" tabindex="-1">GeoFence <a class="header-anchor" href="#geofence" aria-label="Permalink to &quot;GeoFence {#geofence}&quot;">​</a></h3><p>The GeoFence section allows you to define geofence boundaries:</p><ul><li><strong>Polygon Fences</strong> — Add inclusion or exclusion polygon fences. Each polygon can be toggled between inclusion/exclusion, edited, or deleted.</li><li><strong>Circular Fences</strong> — Add inclusion or exclusion circular fences with a configurable radius.</li><li><strong>Breach Return Point</strong> — Optionally set a return point (with altitude) that the vehicle will fly to if it breaches the geofence.</li></ul><h3 id="rally_points" tabindex="-1">Rally Points <a class="header-anchor" href="#rally_points" aria-label="Permalink to &quot;Rally Points {#rally_points}&quot;">​</a></h3><p>The Rally Points section displays and manages rally points. When a rally point is selected, its position fields are shown for editing.</p><h3 id="transform" tabindex="-1">Transform <a class="header-anchor" href="#transform" aria-label="Permalink to &quot;Transform {#transform}&quot;">​</a></h3><p>The Transform section provides tools to adjust the entire mission after it has been created:</p><ul><li><strong>Offset Mission</strong> — Shift the mission by a specified distance in the East, North, and Up directions. Optionally include takeoff and/or landing items in the offset.</li><li><strong>Reposition Mission</strong> — Move the mission to a new location specified by geographic coordinates (Lat/Lon), UTM, MGRS, or the current vehicle position.</li><li><strong>Rotate Mission</strong> — Rotate the mission clockwise by a specified number of degrees. Optionally include takeoff and/or landing items in the rotation.</li></ul><h2 id="stats_terrain" tabindex="-1">Mission Stats / Terrain Panel <a class="header-anchor" href="#stats_terrain" aria-label="Permalink to &quot;Mission Stats / Terrain Panel {#stats_terrain}&quot;">​</a></h2><p>A panel at the bottom of the map provides two toggleable views:</p><ul><li><strong>Terrain Profile</strong> — A chart showing height AMSL vs. distance from start across the mission.</li><li><strong>Mission Statistics</strong> — Displays details for the selected waypoint (altitude difference, azimuth, distance to previous waypoint, gradient, heading) and for the total mission (distance, max telemetry distance, estimated flight time). Battery information (batteries required and change point) is also shown when available.</li></ul><p>Toggle buttons on the left side of the panel let you switch between the terrain profile and mission statistics views, or collapse the panel entirely.</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="plan_transfer_fail" tabindex="-1">Mission (Plan) Upload/Download Failures <a class="header-anchor" href="#plan_transfer_fail" aria-label="Permalink to &quot;Mission (Plan) Upload/Download Failures {#plan_transfer_fail}&quot;">​</a></h3><p>Plan uploading and downloading can fail over a noisy communication link (affecting missions, GeoFence, and rally points). If a failure occurs you should see a status message in the QGC UI similar to:</p><blockquote><p>Mission transfer failed. Retry transfer. Error: Mission write mission count failed, maximum retries exceeded.</p></blockquote><p>The loss rate for your link can be viewed in <a href="./../settings_view/telemetry.html">App Settings &gt; Telemetry</a>. The loss rate should be in the low single digits (i.e. maximum of 2 or 3):</p><ul><li>A loss rate in the high single digits can lead to intermittent failures.</li><li>Higher loss rates often lead to 100% failure.</li></ul><p>There is a much smaller possibility that issues are caused by bugs in either flight stack or QGC. To analyze this possibility you can turn on <a href="./../settings_view/console_logging.html">Console Logging</a> for Plan upload/download and review the protocol message traffic.</p><h2 id="further-info" tabindex="-1">Further Info <a class="header-anchor" href="#further-info" aria-label="Permalink to &quot;Further Info&quot;">​</a></h2><ul><li>New Plan View features for <a href="./../releases/release_note_stable_v3.html#plan-view-v32">QGC release v3.2</a></li><li>New Plan View features for <a href="./../releases/release_note_stable_v3.html#plan-view-v33">QGC release v3.3</a></li></ul>',72)]))}const f=a(s,[["render",l]]);export{g as __pageData,f as default};
